/* Project-local hypermedia runtime for the hx-* features used by this application. */
(()=>{const seen=new WeakSet();function target(el){const q=el.getAttribute('hx-target');return q?document.querySelector(q):el}function triggerHeader(response){const value=response.headers.get('HX-Trigger');if(!value)return;try{const events=JSON.parse(value);Object.entries(events).forEach(([name,detail])=>document.body.dispatchEvent(new CustomEvent(name,{detail}))) }catch(_){document.body.dispatchEvent(new CustomEvent(value))}}async function request(el,event){if(event)event.preventDefault();const method=el.hasAttribute('hx-post')?'POST':'GET';const form=el.tagName==='FORM'?el:el.closest('form');let url=el.getAttribute(method==='POST'?'hx-post':'hx-get');const options={method,headers:{'HX-Request':'true'}};const data=form?new FormData(form):null;if(method==='GET'&&data){const qs=new URLSearchParams(data);url+=`${url.includes('?')?'&':'?'}${qs}`;}else if(data)options.body=data;try{const response=await fetch(url,options);triggerHeader(response);if(response.headers.get('HX-Redirect')){location.href=response.headers.get('HX-Redirect');return}if(response.headers.get('HX-Refresh')==='true'){location.reload();return}if(!response.ok)return;const html=await response.text();const node=target(el);if(!node)return;if(el.getAttribute('hx-swap')==='outerHTML')node.outerHTML=html;else node.innerHTML=html;const push=el.getAttribute('hx-push-url');if(push){const qs=method==='GET'&&data?`?${new URLSearchParams(data)}`:'';history.pushState({},'',(push==='true'?url:push)+qs)}scan(document)}catch(_){document.body.dispatchEvent(new CustomEvent('showToast',{detail:{message:'העדכון נכשל. נסו שוב.',tone:'error'}}))}}function bind(el){if(seen.has(el))return;seen.add(el);const spec=el.getAttribute('hx-trigger')||'';if(spec.includes('every ')){const m=spec.match(/every\s+([\d.]+)s/);if(m)setInterval(()=>document.contains(el)&&request(el),Number(m[1])*1000);return}if(el.tagName==='FORM'){el.addEventListener('submit',e=>request(el,e));if(spec.includes('change'))el.addEventListener('change',e=>request(el,e))}else el.addEventListener('click',e=>request(el,e))}function scan(root){root.querySelectorAll('[hx-get],[hx-post]').forEach(bind)}document.addEventListener('DOMContentLoaded',()=>scan(document));})();
